            Object.keys(value).slice(0, MAX_CONTEXT_OBJECT_KEYS).forEach((key, index) => {
                size += (index > 0 ? 1 : 0) + String(key).length + 3 + estimateContextJsonChars(value[key], depth + 1, seen);
            });
